import React, { useState } from 'react'
import { Avatar, Box, Card, CardActionArea, CardActions, CardContent, CardHeader, CardMedia, Divider, IconButton, Menu, MenuItem, Typography } from '@material-ui/core'
import defaultCoverPhoto from '../images/defaultCoverPhoto.png'
import { makeStyles } from '@material-ui/styles'
import { Link } from 'react-router-dom'
import { MoreVert } from '@material-ui/icons'
import axios from 'axios'


const useStyle = makeStyles(theme => {
  return {
    root: {
      '& .MuiCardActionArea-focusHighlight': {
        background: 'none',
      },
      '& .MuiCardHeader-title': {

        // width: '100%',
        width: theme.spacing(35)
      },
      '& .MuiCardHeader-subheader': {
        whiteSpace: 'nowrap',
        overflow: 'hidden',
        textOverflow: 'ellipsis',

        // width: '100%',
        width: theme.spacing(35)
      },
    },
    avatar: {
      background: '#162276',
      width: theme.spacing(7),
      height: theme.spacing(7),
    },
    media: {
      height: 0,
      paddingTop: '56.25%'
    },
    cardLink: {
      textDecoration: 'none',
      color: 'inherit'
    },
    card: {
      width: theme.spacing(37),
      [theme.breakpoints.down('xs')]: {
        width: theme.spacing(29),
      },
      boxShadow: '',
      transition: 'all ease-out 0.1s',

      '&:hover': {
        // transform: 'scale(1.01)',
        boxShadow: '2px 5px 7px rgba(0, 0, 0, 0.25)',
        transition: 'all ease-out 0.1s',
        [theme.breakpoints.down('md')]: {
          transform: 'none'
        }
      }
    },
    removeBtn: {
      float: 'right',
      backgroundColor: 'rgba(0, 0, 0, 0.2)'
    }
  }
})


export default function ClassroomCards({ subject, showClassrooms }) {
  const classes = useStyle()


  const removePost = () => {

    setOpenMenu(false)
    // axios.post('https://ursacapi.000webhostapp.com/api/removePost.php', subject.id)
    //   .then(res => {
    //     console.log(res.data);
    //     setAnchor(null)
    //     setFocused('');
    //     showClassrooms()

    //   })
    //   .catch(err => console.log(err));
    console.log(subject.id);

  }


  const [focused, setFocused] = useState('');
  const [openMenu, setOpenMenu] = useState(false);
  const [anchor, setAnchor] = useState(null);
  const handleClickMenu = (event) => {
    setOpenMenu(true);
    setAnchor(event.currentTarget)
    setFocused(classes.focus)
  }
  const handleClose = () => {
    setOpenMenu(false)
    setAnchor(null)
    setFocused('')
  }

  return (
    <Box className={classes.root}>
      <Card className={classes.card}>



        <CardMedia
          className={classes.media}
          image={defaultCoverPhoto}
        />
        <CardHeader
          title={
            <Link className={classes.cardLink}
              to={`/teacherFeed/${subject.id}`} >
              {subject.subjectName}
            </Link>
          }
          subheader={subject.yearSection}

        />

        <Divider />

        <CardActions>
          <IconButton className={focused} aria-label="remove" size='small' onClick={handleClickMenu}>
            <MoreVert fontSize='small' />
          </IconButton>
        </CardActions>

        <Menu
          keepMounted
          anchorEl={anchor}
          getContentAnchorEl={null}
          anchorOrigin={{
            vertical: 'bottom',
            horizontal: 'left',
          }}
          transformOrigin={{
            vertical: 'top',
            horizontal: 'left',
          }}
          open={openMenu}
          onClose={handleClose}
          elevation={1}

        >
          <MenuItem dense onClick={removePost}> Remove</MenuItem>
        </Menu>


      </Card>
    </Box>
  )
}
